import{c as a,Q as t,j as o,m as s}from"./chunks/framework.D9IbVcwA.js";const b=JSON.parse('{"title":"004-boot-load-mini-kernel-c-3 · 内核加载 (C)","description":"","frontmatter":{"title":"004-boot-load-mini-kernel-c-3 · 内核加载 (C)"},"headers":[],"relativePath":"tutorial/004-boot-load-mini-kernel-c-3.md","filePath":"tutorial/004-boot-load-mini-kernel-c-3.md","lastUpdated":1779686691000}'),d={name:"tutorial/004-boot-load-mini-kernel-c-3.md"};function n(i,e,c,l,r,p){return t(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="内核的第一次呼吸-下-构建系统深度剖析与跨-os-对比" tabindex="-1">内核的第一次呼吸（下）：构建系统深度剖析与跨 OS 对比 <a class="header-anchor" href="#内核的第一次呼吸-下-构建系统深度剖析与跨-os-对比" aria-label="Permalink to &quot;内核的第一次呼吸（下）：构建系统深度剖析与跨 OS 对比&quot;">​</a></h1><blockquote><p>标签：build system, CMake, mcmodel, linker script, objcopy, debugcon, OS comparison 前置：<a href="./004-boot-load-mini-kernel-c-2">004C-2 内核的第一次呼吸</a></p></blockquote><h2 id="写在前面" tabindex="-1">写在前面 <a class="header-anchor" href="#写在前面" aria-label="Permalink to &quot;写在前面&quot;">​</a></h2><p>前两篇我们把 004C tag 的核心代码都讲完了——从 BootInfo 填充和高半核跳转，到 boot.S 的入口序列、BSS 清除陷阱、符号冲突侦探故事，再到 crt_stub.cpp 的 C++ 运行时支撑和 mini_kernel_main 的特性验证。这一篇换一个角度，从构建系统和验证的角度重新审视这些代码，同时横向对比 Linux、xv6 和 SerenityOS 在相同问题上的不同选择。</p><p>为什么要专门花一篇来讲构建系统？因为在内核开发中，编译选项和链接脚本不是&quot;配置文件&quot;那么简单——它们是代码的一部分。一个 <code>-mcmodel</code> 选错了，代码编译和链接都不报错，运行时直接暴毙。一个链接脚本段的顺序搞反了，BSS 清除会误伤 <code>.data</code> 段的变量。这些问题的根因都不在逻辑层面，而在构建配置层面，排查起来特别耗时间。</p><h2 id="环境说明" tabindex="-1">环境说明 <a class="header-anchor" href="#环境说明" aria-label="Permalink to &quot;环境说明&quot;">​</a></h2><p>构建工具链版本：GCC 13+（需要支持 C++23 特性，虽然当前 tag 只用了 C++17 的基础特性）、CMake 3.20+、GNU Binutils（提供 objcopy 和 ld）。目标三元组是 x86_64-elf（freestanding，不依赖任何系统头文件和库）。</p><h2 id="cmakelists-txt-每一个选项都是血的教训" tabindex="-1">CMakeLists.txt：每一个选项都是血的教训 <a class="header-anchor" href="#cmakelists-txt-每一个选项都是血的教训" aria-label="Permalink to &quot;CMakeLists.txt：每一个选项都是血的教训&quot;">​</a></h2><p>Mini Kernel 的构建系统定义在 <code>kernel/mini/CMakeLists.txt</code> 中。这个文件看起来很简单——三个源文件、几个编译选项、一个链接脚本、一个 objcopy 后处理——但每一个选项背后都有一个&quot;不选就会出事&quot;的故事。</p><h3 id="源文件列表" tabindex="-1">源文件列表 <a class="header-anchor" href="#源文件列表" aria-label="Permalink to &quot;源文件列表&quot;">​</a></h3><div class="language-makefile vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">makefile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">add_library(mini_kernel_common OBJECT</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    arch/x86_64/boot.S</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    arch/x86_64/crt_stub.cpp</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    arch/x86_64/gdt.cpp</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    arch/x86_64/idt.cpp</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ...</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    main.cpp</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>源文件用 OBJECT 库组织，这样测试目标（CMakeLists.txt 在 test/ 子目录下）和生产目标可以共享同一份源文件编译结果，避免重复编译。<code>boot.S</code> 的 <code>.S</code> 后缀会被 CMake 自动识别为需要 C 预处理的汇编文件——和 <code>.s</code>（小写）不同，后者不经过预处理。这意味着 <code>boot.S</code> 里可以用 <code>#include</code> 引入头文件、用 <code>#define</code> 定义常量。</p><h3 id="编译选项逐一解读" tabindex="-1">编译选项逐一解读 <a class="header-anchor" href="#编译选项逐一解读" aria-label="Permalink to &quot;编译选项逐一解读&quot;">​</a></h3><div class="language-makefile vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">makefile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">set(MINI_KERNEL_COMMON_COMPILE_OPTIONS</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    -ffreestanding</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    -fno-exceptions</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    -fno-rtti</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    -fno-pie</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    -mcmodel=large</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    -mno-red-zone</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    -Wall</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p><strong><code>-ffreestanding</code></strong> 告诉编译器这是 freestanding 环境。在 hosted 环境下（普通应用程序），编译器可以假定标准库函数存在并生成隐式调用。比如 <code>memcpy</code> 可能被编译器内联展开为 <code>rep movsb</code>，但如果你在 freestanding 环境下没有提供 <code>memcpy</code> 的实现，链接就会失败。加上这个选项后，编译器不再做这种假设。它同时意味着 <code>main</code> 函数不再有特殊语义——我们的入口函数叫 <code>_start</code> 而不是 <code>main</code>，链接器通过 <code>ENTRY(_start)</code> 来确定入口点。</p><p><strong><code>-fno-exceptions -fno-rtti</code></strong> 这两个选项禁用 C++ 的异常和运行时类型信息。异常需要 <code>.eh_frame</code> 段和栈展开（stack unwinding）基础设施——内核中我们没有这些。RTTI 需要 <code>typeid</code> 的额外数据，增加代码体积。SerenityOS 也使用相同的选项组合——内核中的错误处理用 <code>ErrorOr&lt;T&gt;</code> 返回值而不是异常。值得注意的是，<code>-fno-exceptions</code> 会让 <code>throw</code> 语句变成编译错误，但 <code>catch</code> 块在某些编译器版本下可能仍然被接受（只是永远不会执行到）——所以如果你发现某些 C++ 代码在内核中编译报错，首先检查是不是用了异常相关的特性。</p><p><strong><code>-mcmodel=large</code></strong> 这是高半核内核的硬性要求。x86-64 的默认代码模型是 <code>small</code>，它假设所有符号都在低 2GB 地址空间内（0 到 0x7FFFFFFF），编译器用 32 位 RIP-relative 寻址来访问全局变量——指令编码只有 7 字节（REX 前缀 + 操作码 + 32 位位移）。但我们的内核 VMA 是 <code>0xFFFFFFFF80000000</code>，远超 2GB 范围。<code>large</code> 模型下，编译器对每个全局变量访问都用 <code>movabsq $64bit_addr, %rax</code> + 间接寻址，指令编码变成 10 字节。代价是代码体积增大（每条全局变量访问多 3-5 字节），但安全。</p><p>如果你忘了加这个选项会怎样？编译和链接都正常通过，没有任何警告。但运行时，所有高半核地址的引用都会被截断成 32 位值，变成完全错误的地址。而且崩溃的位置和根因完全不相关——你可能花了半天才发现问题出在编译选项上。</p><p><strong><code>-mno-red-zone</code></strong> 禁用 x86-64 的 Red Zone 优化。Red Zone 是 ABI 定义的栈指针以下 128 字节保留区域，用户态函数可以用它存储临时数据而不调整 <code>%rsp</code>。但在内核代码中，硬件中断可能在任何指令处打断执行——中断处理程序直接使用当前栈，会覆盖 Red Zone 的内容。如果编译器把某个关键变量存在了 Red Zone 里，中断到来时数据就被破坏了。这个问题的特征是&quot;某些时候正常、某些时候崩溃&quot;——因为中断的时机是随机的，只有在 Red Zone 里的数据恰好被中断覆盖时才会出问题。排查这种 bug 的难度极高，所以一定要从一开始就禁用 Red Zone。</p><h3 id="链接选项和后处理" tabindex="-1">链接选项和后处理 <a class="header-anchor" href="#链接选项和后处理" aria-label="Permalink to &quot;链接选项和后处理&quot;">​</a></h3><div class="language-makefile vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">makefile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">target_link_options(mini_kernel PRIVATE</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    -T </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">\${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CMAKE_CURRENT_SOURCE_DIR</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/linker.ld</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    -nostdlib</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    -no-pie</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">add_custom_command(TARGET mini_kernel</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    POST_BUILD</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    COMMAND</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> objcopy</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> -O</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> binary</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">TARGET_FILE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:mini_kernel&gt;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        $&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">TARGET_FILE_DIR</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:mini_kernel&gt;/mini_kernel.bin</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    VERBATIM</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p><code>-nostdlib</code> 不链接标准库和启动文件（crt0.o、crti.o 等）。这很重要——如果忘了加这个选项，链接器会尝试链接 glibc 的启动代码，然后因为找不到 <code>__libc_start_main</code> 而报错。即使链接成功了，glibc 的初始化代码也会试图调用我们没实现的系统调用，导致内核直接崩溃。<code>-no-pie</code> 禁用位置无关可执行文件——内核地址在链接时确定，不需要运行时重定位。</p><p>objcopy 后处理把 ELF 转成 flat binary。这一步有几个需要注意的点：ELF 的 section header table、program header table、符号表、重定位信息全部被剥离；输出只包含可加载段（<code>.text</code>、<code>.data</code>、<code>.init_array</code>）的原始二进制内容；<code>.bss</code> 段不包含在输出中（它在 ELF 里不占空间）。Bootloader 不知道 ELF 是什么——它只是把磁盘上的二进制数据原封不动读到物理地址 0x20000 然后跳转。</p><h3 id="链接脚本中的-text-start-段排列技巧" tabindex="-1">链接脚本中的 .text.start 段排列技巧 <a class="header-anchor" href="#链接脚本中的-text-start-段排列技巧" aria-label="Permalink to &quot;链接脚本中的 .text.start 段排列技巧&quot;">​</a></h3><p>这里有一个很多教程不会讲到的细节：_start 必须是 flat binary 的第一个字节。如果不做特殊处理，链接器可能把其他函数（比如 __cxa_pure_virtual 或某个类的成员函数）放在输出文件的开头——链接器的段合并顺序并不总是和源文件列表顺序一致。</p><p>Cinux 的解决方案是使用 .text.start 子段。在 boot.S 中，_start 被放在 .section .text.start, &quot;ax&quot; 段（注意 &quot;ax&quot; 表示 allocatable + executable）。在链接脚本中，.text 段的第一行就是 *(.text.start)——通配符 <em>(.text .text.</em>) 放在后面。这保证了链接器首先排放 .text.start 段的内容，也就是 _start 的代码。这是 flat binary 内核开发中的标准技巧——Linux 使用类似的 __HEAD .section .head.text 来确保 startup_64 在文件最前面。</p><h2 id="debugcon-从调试工具到核心验证基础设施" tabindex="-1">debugcon：从调试工具到核心验证基础设施 <a class="header-anchor" href="#debugcon-从调试工具到核心验证基础设施" aria-label="Permalink to &quot;debugcon：从调试工具到核心验证基础设施&quot;">​</a></h2><p><code>cmake/qemu.cmake</code> 的一个小变更体现了 004C tag 的设计理念转变：debugcon 从&quot;调试工具&quot;升级为&quot;核心验证基础设施&quot;。</p><p>之前 debugcon 只在 <code>QEMU_DEBUG_FLAGS</code> 中启用（<code>make run-debug</code>），正常 <code>make run</code> 不启用。这在 003 章没问题——debugcon 输出只是辅助调试。但从 004C 开始，内核的 <code>boot.S</code> 和 <code>main.cpp</code> 用 debugcon 输出字符序列来验证每一步执行是否正确。这个序列（<code>OPLJ123G4===CPPGC1V123B===END</code>）不是&quot;调试信息&quot;，而是&quot;功能验证&quot;——如果某个字符缺失，就说明对应的功能有 bug。</p><p>把它移到 <code>QEMU_COMMON_FLAGS</code> 后，所有运行模式都能看到输出。QEMU 参数 <code>-debugcon file:debug.log</code> 指定输出到文件，<code>-global isa-debugcon.iobase=0xe9</code> 显式绑定端口。这种&quot;从调试工具到验证基础设施&quot;的演进在内核开发中很常见——Linux 内核的 <code>pr_debug</code>、<code>printk</code> 也是类似的发展路径，最初只是为了调试，后来变成了生产环境可观测性的基础。</p><p>debugcon 的 I/O 端口 0xE9 是 Bochs 模拟器最早引入的调试端口，后来 QEMU 也支持了。往这个端口写一个字节，QEMU 会把它输出到 debugcon 设备。<code>outb %al, $0xE9</code> 这条 2 字节的指令就是所有的硬件开销——比串口 UART 简单得多（UART 需要初始化波特率、检查发送缓冲区是否空闲等），这也是我们选择 debugcon 而不是串口作为早期验证输出的原因。</p><h2 id="跨-os-对比-同一问题的不同解法" tabindex="-1">跨 OS 对比：同一问题的不同解法 <a class="header-anchor" href="#跨-os-对比-同一问题的不同解法" aria-label="Permalink to &quot;跨 OS 对比：同一问题的不同解法&quot;">​</a></h2><h3 id="内核入口序列" tabindex="-1">内核入口序列 <a class="header-anchor" href="#内核入口序列" aria-label="Permalink to &quot;内核入口序列&quot;">​</a></h3><table tabindex="0"><thead><tr><th>步骤</th><th>Cinux (004C)</th><th>Linux (head_64.S)</th><th>xv6 (entry.S)</th></tr></thead><tbody><tr><td>关中断</td><td><code>cli</code></td><td><code>cli</code>（decompressor 已关）</td><td>无（依赖 GRUB）</td></tr><tr><td>SSE 启用</td><td>CR4 设置 OSFXSR+OSXMMEXCPT</td><td>内核启动后由 <code>fpu__init</code> 完成</td><td>不需要（纯 C）</td></tr><tr><td>设栈</td><td><code>__mini_stack_top</code>（.bss 末尾）</td><td><code>initial_stack</code>（定义在 head_64.S）</td><td><code>stack</code>（定义在 entry.S）</td></tr><tr><td>BSS 清除</td><td><code>rep stosb</code>（自写）</td><td>decompressor 清零 + <code>__bss_start/__bss_end</code></td><td>GRUB 保证清零</td></tr><tr><td>全局构造函数</td><td><code>_init_global_ctors</code>（遍历 .init_array）</td><td><code>do_initcalls</code>（多级 initcall）</td><td>不需要（纯 C）</td></tr><tr><td>BootInfo 传递</td><td><code>%rdi</code> -&gt; <code>.data</code> 段</td><td><code>%rsi</code> -&gt; <code>%r15</code> 寄存器</td><td>不需要</td></tr></tbody></table><h3 id="高半核设计" tabindex="-1">高半核设计 <a class="header-anchor" href="#高半核设计" aria-label="Permalink to &quot;高半核设计&quot;">​</a></h3><table tabindex="0"><thead><tr><th>OS</th><th>高半核基址</th><th>页表策略</th><th>5-level paging</th></tr></thead><tbody><tr><td>Cinux</td><td><code>0xFFFFFFFF80000000</code></td><td>复用 identity mapping 的 PD</td><td>不支持</td></tr><tr><td>Linux</td><td><code>0xFFFFFFFF80000000</code></td><td>独立内核页表（init_top_pgt）</td><td>支持（KASLR）</td></tr><tr><td>SerenityOS</td><td><code>0xFFFFFFFF80000000</code></td><td>独立内核页表</td><td>不支持</td></tr><tr><td>xv6</td><td>无（identity mapping）</td><td>无</td><td>不适用</td></tr></tbody></table><h3 id="c-运行时策略" tabindex="-1">C++ 运行时策略 <a class="header-anchor" href="#c-运行时策略" aria-label="Permalink to &quot;C++ 运行时策略&quot;">​</a></h3><table tabindex="0"><thead><tr><th>特性</th><th>Cinux</th><th>SerenityOS</th></tr></thead><tbody><tr><td>异常</td><td>禁用 (<code>-fno-exceptions</code>)</td><td>禁用，使用 <code>ErrorOr&lt;T&gt;</code></td></tr><tr><td>RTTI</td><td>禁用 (<code>-fno-rtti</code>)</td><td>禁用</td></tr><tr><td>全局构造函数</td><td><code>.init_array</code> 直接遍历</td><td>类似机制</td></tr><tr><td>new/delete</td><td>halt stub</td><td>真正的 kmalloc/kfree</td></tr><tr><td>构建系统</td><td>CMake</td><td>CMake + Serenity&#39;s MetaData</td></tr></tbody></table><h2 id="objcopy-深度剖析-从-elf-到-flat-binary-发生了什么" tabindex="-1">objcopy 深度剖析：从 ELF 到 Flat Binary 发生了什么 <a class="header-anchor" href="#objcopy-深度剖析-从-elf-到-flat-binary-发生了什么" aria-label="Permalink to &quot;objcopy 深度剖析：从 ELF 到 Flat Binary 发生了什么&quot;">​</a></h2><p>理解 objcopy 的工作方式对排查构建问题至关重要。让我们用实际命令来看看转换前后发生了什么变化。</p><p>首先是 ELF 文件的段布局：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">readelf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build/kernel/mini/mini_kernel</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>输出会显示大约 10-15 个段，包括 <code>.text.start</code>、<code>.text</code>、<code>.rodata</code>、<code>.data</code>、<code>.init_array</code>、<code>.bss</code> 等。每个段都有 <code>Addr</code>（VMA）、<code>Offset</code>（文件内偏移）和 <code>Size</code>。注意 <code>.bss</code> 段的 <code>Size</code> 不为零但 <code>Offset</code> 指向文件末尾之后——这意味着它不占磁盘空间。</p><p>执行 <code>objcopy -O binary</code> 后，所有这些段的原始二进制内容被提取出来，按 LMA（物理地址）排序，拼接成一个连续的文件。section header、program header、符号表、字符串表、重定位表全部丢弃。输出文件的第一字节对应 ELF 中最低 LMA 的段的第一个字节。</p><p>有一个细节值得注意：objcopy 在计算 flat binary 的布局时使用的是 LMA（<code>AT()</code> 指定的物理地址），而不是 VMA。在我们的链接脚本中，所有段的 LMA 都用 <code>ADDR(.xxx) - KERNEL_Virt_BASE</code> 计算，这意味着 <code>.text</code> 从 LMA 0x20000 开始，<code>.data</code> 从 LMA <code>0x20000 + SIZEOF(.text)</code> 开始，<code>.init_array</code> 紧随其后。由于 flat binary 的第一个字节对应最低 LMA，而我们的最低 LMA 是 0x20000，objcopy 实际上输出的文件从&quot;相对偏移 0&quot;开始——也就是说，flat binary 的第 0 字节对应物理地址 0x20000，第 N 字节对应物理地址 0x20000 + N。Bootloader 把整个文件加载到物理地址 0x20000 后，每个字节就自动到了正确的物理位置。</p><p>如果 objcopy 的输出看起来太大或者太小，可以用 <code>readelf -l</code> 检查 ELF 的 program header 中的 <code>FileSiz</code> 和 <code>MemSiz</code> 列——flat binary 的大小应该等于所有可加载段 FileSiz 的总和（加上段之间的对齐填充）。</p><h2 id="debugcon-输出序列的完整解读" tabindex="-1">debugcon 输出序列的完整解读 <a class="header-anchor" href="#debugcon-输出序列的完整解读" aria-label="Permalink to &quot;debugcon 输出序列的完整解读&quot;">​</a></h2><p><code>OPLJ123G4===CPPGC1V123B===END</code> 这个 30 字符序列是 004C tag 的完整验证标准。让我们完整拆解每个字符的来源和含义。</p><p><code>O</code> 来自 <code>boot/stage2.S</code>，在 MBR 把 Stage2 加载到 0x8000 并跳转后输出。<code>P</code> 来自 <code>boot/stage2.S</code> 的 <code>pm_entry</code> 标签，保护模式切换完成后输出。<code>L</code> 来自 <code>boot/common/long_mode.S</code> 的 <code>long_mode_entry</code> 标签，Long Mode 进入后输出。<code>J</code> 来自 <code>boot/stage2.S</code> 的 BootInfo 填充代码末尾，跳转到内核前输出。</p><p><code>1</code> 来自 <code>kernel/mini/arch/x86_64/boot.S</code> 的 <code>_start</code> 入口，SSE 启用后输出。<code>2</code> 同样来自 boot.S，栈设置完成后输出。<code>3</code> 来自 boot.S，BSS 清除（<code>rep stosb</code>）完成后输出。<code>G</code> 来自 <code>kernel/mini/main.cpp</code> 的 <code>GlobalCounter</code> 构造函数，在 <code>_init_global_ctors</code> 遍历 <code>.init_array</code> 时输出。<code>4</code> 来自 boot.S，全局构造函数调用完毕后输出。</p><p><code>===CPP</code> 是 <code>mini_kernel_main</code> 的开始标记。<code>C1</code> 是 <code>SimpleClass</code> 构造函数输出。<code>V</code> 是 <code>Derived</code> 构造函数输出。<code>2</code> 是虚函数测试通过。<code>3</code> 是全局对象验证通过。<code>B</code> 是 BootInfo 验证通过。<code>===END</code> 是结束标记。</p><p>如果序列在某处中断，定位方法很简单：找到最后一个出现的字符，它的下一步就是出错的位置。</p><h2 id="验证清单" tabindex="-1">验证清单 <a class="header-anchor" href="#验证清单" aria-label="Permalink to &quot;验证清单&quot;">​</a></h2><p>完整构建后，按以下清单逐项验证：</p><ol><li><code>build/kernel/mini/mini_kernel</code> 是 ELF 64-bit x86-64（<code>file</code> 命令确认）</li><li>入口地址是 <code>0xffffffff80020000</code>（<code>readelf -h</code> 确认）</li><li><code>.init_array</code> 段存在且不为空（<code>readelf -S</code> 确认）</li><li><code>__boot_info_ptr</code> 在 <code>.data</code> 段，不在 <code>.bss</code> 段（<code>objdump -t</code> 确认）</li><li><code>mini_kernel.bin</code> 存在且大小合理（几十 KB）</li><li><code>debug.log</code> 包含完整序列 <code>OPLJ123G4===CPPGC1V123B===END</code></li></ol><p>每一步的失败模式都不一样：第 3 步失败说明 <code>KEEP()</code> 没写对——链接器的 section garbage collection 把 <code>.init_array</code> 砍掉了，全局构造函数永远不会被调用；第 4 步失败说明 <code>__boot_info_ptr</code> 的段定义有误——如果它在 <code>.bss</code> 段，BSS 清除会把它清零或者和其他符号冲突；第 6 步失败需要根据最后一个出现的字符来定位具体是哪个阶段出了问题。</p><p>如果所有检查都通过但 debug.log 里还是没有完整序列，最后检查一下磁盘镜像是否正确生成了——<code>build_image.sh</code> 脚本需要把 MBR 写入 LBA 0、Stage2 写入 LBA 1 开始的扇区、Mini Kernel flat binary 写入 LBA 16 开始的扇区。任何一步写错了位置，Bootloader 都会跳到错误的地址。</p><h2 id="收尾" tabindex="-1">收尾 <a class="header-anchor" href="#收尾" aria-label="Permalink to &quot;收尾&quot;">​</a></h2><p>004C 这个 tag 把从 Bootloader 到 C++ 内核的整条启动链路全部打通了。构建系统虽然看起来只是&quot;配置文件&quot;，但 <code>-mcmodel=large</code> 和 <code>-mno-red-zone</code> 这种选项漏了任何一个都会导致运行时崩溃，而且编译链接阶段不会有任何报错。debugcon 从调试工具升级为验证基础设施，体现了&quot;内核开发中每一步都要可观测&quot;的原则。</p><p>与 Linux、xv6、SerenityOS 的横向对比揭示了一个有趣的规律：所有高半核内核都选了 <code>0xFFFFFFFF80000000</code> 这个地址，但页表策略、BSS 清除方式、全局构造函数调用机制各有不同。这些差异不是随机的——它们反映的是项目规模、目标硬件、开发语言选择之间的权衡。Cinux 的&quot;复用 PD + 自清 BSS + .init_array 遍历&quot;组合，是一个教学内核在资源受限和概念简洁性之间的最优解。</p><p>当你后面回过头来重构这段代码时——比如把 bootloader 的页表替换为内核自己管理的页表，或者把 halt 版的 new/delete 替换为真正的堆分配器——你会感激当初选择了这种清晰的分层设计。每一层只做一件事，每一层都有独立的验证手段（debugcon 的字符输出），这使得后续的重构和扩展可以在可控的范围内进行。</p><p>从 004A 到 004C，我们完成了整个 Bootloader 到内核的启动链路。004A 在 Real Mode 下做 E820 探测和磁盘读取，004B 定义 BootInfo 结构体并把磁盘读取从 4KB 扩展到 416KB，004C 在 Long Mode 下填充 BootInfo、建立高半核映射、跳转到内核、完成 C++ 运行时初始化。每一步都有清晰的 tag 边界和验证标准。接下来的 tag 将会让内核开始做真正有用的事情——建立中断处理、实现物理内存管理、加载真正的内核。到那时，我们今天搭好的 C++ 运行时和 BootInfo 传递机制就会派上真正的用场了。到那时回头看这几十行汇编代码，你会发现它们虽然简单，却承载了整个系统启动过程中最关键的一环。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><p>Intel 64 and IA-32 Architectures Software Developer&#39;s Manual, Vol. 3A, Section 4.3 -- 4-Level Paging: 4 级页表结构和 2MB 大页设置。 <a href="https://www.intel.com/content/www/us/en/developer/articles/technical/intel-sdm.html" target="_blank" rel="noreferrer">https://www.intel.com/content/www/us/en/developer/articles/technical/intel-sdm.html</a></p></li><li><p>System V Application Binary Interface, AMD64 Architecture Processor Supplement: 函数调用约定和 Red Zone 定义。 <a href="https://gitlab.com/x86-psABIs/x86-64-ABI" target="_blank" rel="noreferrer">https://gitlab.com/x86-psABIs/x86-64-ABI</a></p></li><li><p>OSDev Wiki -- C++ Bare Bones: freestanding 环境下的 C++ 内核设置。 <a href="https://wiki.osdev.org/C%2B%2B_Bare_Bones" target="_blank" rel="noreferrer">https://wiki.osdev.org/C%2B%2B_Bare_Bones</a></p></li><li><p>Linux Kernel <code>arch/x86/kernel/head_64.S</code>: Linux 的 <code>startup_64</code> 入口序列。 <a href="https://github.com/torvalds/linux/blob/master/arch/x86/kernel/head_64.S" target="_blank" rel="noreferrer">https://github.com/torvalds/linux/blob/master/arch/x86/kernel/head_64.S</a></p></li><li><p>SerenityOS Kernel: 另一个使用 C++ 的开源操作系统内核，同样使用 <code>-ffreestanding -fno-exceptions -fno-rtti</code>。 <a href="https://github.com/SerenityOS/serenity" target="_blank" rel="noreferrer">https://github.com/SerenityOS/serenity</a></p></li><li><p>xv6 <code>entry.S</code> (MIT): 纯 C 内核的简化入口，对比 C++ 内核的额外复杂度。 <a href="https://github.com/mit-pdos/xv6-public/blob/master/entry.S" target="_blank" rel="noreferrer">https://github.com/mit-pdos/xv6-public/blob/master/entry.S</a></p></li></ul>`,64)])])}const k=a(d,[["render",n]]);export{b as __pageData,k as default};
